// Goal Counter
var count = 0;
var goalCounter = document.getElementById('goal_counter');
var goalCounterBalls = document.getElementById('goal_counter_balls')
// Get the element ID from the document page
var ball = document.getElementById('ball')
var shootLeftBtn = document.getElementById('shoot_left'); // Shoot left button
var shootCenterBtn = document.getElementById('shoot_center'); // shoot right button 
