function init() {
    // while (goalCounter === 2) {
    //     window.location.reload();
    // }
    goalCounter.innerHTML = count;

}

function keeperActions(randomJump, direction) {
    const jump = keeper[randomJump].id;
    console.log(`jump=${jump}, direction=${direction}`)

    keeper[randomJump].classList.add("keeper_dive_right");
    if (jump === direction) {
        console.log("Goal")
        count = count + 1
        goalCounter.innerHTML = count;
        goalCounterBalls.innerHTML += `<li>
        <img src="./assets/img/green-ball.png" height="30px">
        </li>`

    } else {
        console.log("Missed ")
        goalCounterBalls.innerHTML += `<li>
        <img src="./assets/img/red-ball.png" height="30px">
        </li>`
    }
    console.log(count)
}

// Functions for the buttons
function shootLeft() {
    const random = RandomJumpFun()
    keeperActions(random, "left")
    ball.className = "";
    ball.classList.add("ball_left_animation");
}

function shootRight() {
    const random = RandomJumpFun()
    keeperActions(random, "right")
    ball.className = "";
    ball.classList.add("ball_right_animation");
}

function shootCenter() {
    const random = RandomJumpFun()
    keeperActions(random, "center")
    ball.className = "";
    ball.classList.add("ball_center_animation");
}



// Generate Random Dive

function RandomJumpFun() {
    const randomAction = Math.floor(Math.random() * 3);
    return randomAction
}